const fs = require('fs');
const path = require('path');
const projects = ['escape-the-dungeon', 'gad-explainer-video'];
const speciesNames = ['gad', 'bare', 'emergent'];

for (const project of projects) {
  for (const species of speciesNames) {
    const file = path.join('evals', project, 'species', species, 'gad.json');
    const data = JSON.parse(fs.readFileSync(file, 'utf8'));
    // Drop dropped fields
    delete data.eval_mode;
    // Update name to canonical species name
    data.name = species;
    data.species = species;
    data.project = project;
    data.context_framework = species; // gad, bare, emergent are first-class context frameworks
    // Drop compare_to (no longer meaningful — siblings are auto-discovered now)
    delete data.compare_to;
    // Update inherits_from to the new shape (species name, not full project name)
    if (data.inherits_from) {
      // 'escape-the-dungeon-bare' -> 'bare'
      const m = data.inherits_from.match(/-(bare|emergent|gad)\$/);
      if (m) data.inherits_from = m[1];
    }
    // Update baseline.project if present
    if (data.baseline && data.baseline.project) {
      const m = data.baseline.project.match(/-(bare|emergent|gad)\$/);
      if (m) {
        data.baseline.species = m[1];
        data.baseline.project = project;
      }
    }
    fs.writeFileSync(file, JSON.stringify(data, null, 2) + '\n');
    console.log('updated', file);
  }
}

// Write project.json for each parent project
const projectMeta = {
  'escape-the-dungeon': {
    name: 'Escape the Dungeon',
    slug: 'escape-the-dungeon',
    description: 'A roguelite dungeon-crawler the agent must implement end-to-end. The canonical implementation eval — used to test framework / context-framework / DNA hypotheses across multiple species.',
    domain: 'game',
    techStack: 'kaplay',
    tagline: null,
    cardImage: null,
    heroImage: null
  },
  'gad-explainer-video': {
    name: 'GAD Explainer Video',
    slug: 'gad-explainer-video',
    description: 'A Remotion-rendered explainer video for the GAD framework. The non-game eval domain — tests whether framework / context-framework hypotheses generalize beyond game implementation.',
    domain: 'video',
    techStack: 'remotion',
    tagline: null,
    cardImage: null,
    heroImage: null
  }
};
for (const [slug, meta] of Object.entries(projectMeta)) {
  const file = path.join('evals', slug, 'project.json');
  fs.writeFileSync(file, JSON.stringify(meta, null, 2) + '\n');
  console.log('wrote', file);
}
