const fs = require('fs');
const path = require('path');
function walk(dir, out=[]) {
  for (const e of fs.readdirSync(dir, { withFileTypes: true })) {
    if (e.name === 'node_modules' || e.name === '.next') continue;
    const p = path.join(dir, e.name);
    if (e.isDirectory()) walk(p, out);
    else if (/\.(tsx|ts|md|mdx)$/.test(e.name)) out.push(p);
  }
  return out;
}
const files = [
  ...walk('site/app'),
  ...walk('site/components'),
];
let touched = 0;
const skip = new Set([
  // historical content/data files we leave alone
  'site/components/landing/projects/projects-shared.ts',
]);
for (const f of files) {
  if (skip.has(f.replace(/\\/g, '/'))) continue;
  let src = fs.readFileSync(f, 'utf8');
  const before = src;
  // Display copy: drop "greenfield" qualifier where it's just an adjective
  src = src.replace(/\bgreenfield runs?\b/g, 'runs');
  src = src.replace(/\bgreenfield run\b/g, 'run');
  src = src.replace(/\ba greenfield\b/g, 'a');
  src = src.replace(/\bgreenfield emergent\b/g, 'emergent');
  src = src.replace(/\bgreenfield project\b/g, 'project');
  src = src.replace(/\bevery greenfield\b/g, 'every');
  // Brownfield: deleted entirely as a concept; rare incidental copy
  src = src.replace(/\bGreenfield → brownfield lineage\b/g, 'Eval lineage');
  src = src.replace(/\bbrownfield extension,?\s*/g, '');
  src = src.replace(/\bbrownfield evals\b/g, 'evals');
  src = src.replace(/\bBrownfield evals\b/g, 'Evals');
  src = src.replace(/\bbrownfield conditions?\b/g, 'evals');
  src = src.replace(/\bBrownfield conditions?\b/g, 'Evals');
  // Remove standalone "greenfield" in JSX text where it stuck around
  src = src.replace(/\bgreenfield v(\d+)\b/g, 'v$1');
  if (src !== before) {
    fs.writeFileSync(f, src);
    touched++;
    console.log('updated', f);
  }
}
console.log('total touched', touched);

