      if (!exists(speciesJsonPath)) continue;
      out.push({
        project: projectName,
        species: speciesName,
        // composite id used downstream as a stable key for species rows
        id: `${projectName}/${speciesName}`,
        dir,
        projectDir,
        speciesJsonPath,
        templateDir: path.join(dir, "template"),
      });
    }
  }
