      className="block rounded-lg border border-[var(--border)] bg-[var(--card)] p-5 transition-colors hover:border-[var(--accent)]"
    >
      <div className="flex items-baseline justify-between gap-3">
        <h2 className="text-xl font-semibold tracking-tight text-white">
          {g.project}
        </h2>
        <span className="rounded-md border border-[var(--border)] px-2 py-0.5 text-xs uppercase tracking-wide text-[var(--muted)]">
          {g.species}
        </span>
      </div>
      <div className="mt-1 flex items-baseline gap-2 text-sm">
        <span className="font-mono text-[var(--accent)]">{g.version}</span>
        <span className="text-[var(--muted)]">·</span>
        <span
          className="text-[var(--muted)]"
          title={g.createdAt.toISOString()}
        >
          {formatRelative(g.createdAt)} (approx)
        </span>
      </div>
      <div
        className="mt-3 truncate font-mono text-xs text-[var(--muted)]"
        title={g.worktreePath}
      >
        {g.worktreePath}
      </div>
      {g.lineageParent ? (
        <div className="mt-2 text-xs text-[var(--muted)]">
          lineage: {g.lineageParent.project}/{g.lineageParent.species}/
          {g.lineageParent.version}
        </div>
      ) : null}
    </Link>
  );
}

