function dedupe(gens: Generation[]): Generation[] {
  const seen = new Set<string>();
  const out: Generation[] = [];
  for (const g of gens) {
    const key = `${g.project}/${g.species}/${g.version}`;
    if (seen.has(key)) continue;
    seen.add(key);
    out.push(g);
  }
  return out;
}

function sortGenerations(gens: Generation[]): Generation[] {
  return [...gens].sort((a, b) => {
    if (a.project !== b.project) return a.project.localeCompare(b.project);
    if (a.species !== b.species) return a.species.localeCompare(b.species);
    // Version desc (newest first). Strip leading v, compare numerically.
    const av = Number(a.version.replace(/^v/, ""));
    const bv = Number(b.version.replace(/^v/, ""));
    if (Number.isFinite(av) && Number.isFinite(bv)) return bv - av;
    return b.version.localeCompare(a.version);
  });
}

export async function getGenerations(): Promise<Generation[]> {
  const monorepoRoot = resolveMonorepoRoot();
  const roots = evalRoots(monorepoRoot);
  const all: Generation[] = [];
  for (const root of roots) all.push(...collectFromRoot(root));
  return sortGenerations(dedupe(all));
}

export async function getGenerationByKey(
  project: string,
  species: string,
  version: string,
): Promise<Generation | null> {
  const gens = await getGenerations();
  return (
    gens.find(
      (g) => g.project === project && g.species === species && g.version === version,
    ) ?? null
  );
}
