  const siteDir = process.cwd();
  const repoRoot = path.resolve(siteDir, "..", "..", "..");
  const gadBin = path.resolve(siteDir, "..", "bin", "gad.cjs");

  const args = [gadBin, "eval", "run", "--project", projectId];
